import itertools
import logging
import os
from typing import Dict, Set, Any, List, Sequence, Optional, Mapping

from geosat.cloud import PointCloud
from geosat.cloud.io import KNOWN_FORMATS
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from geosat.psanp.abstractions.stage import Stage
from geosat.psanp.abstractions.types import ClassificationMap
from geosat.tools.urlprotocol import UrlProtocols

from psanp.classifiers.sequence_classifier import SequenceClassifier

logger = logging.getLogger(__name__)


def get_missing_classes(
    classification_code: ClassificationMap,
    input_classes: Set[str],
    output_classes: Set[str],
) -> Set[str]:
    """Returns the classes from the 'input_classes' and 'output_classes'
    that are missing from the classification map.
    """
    needed_classes = itertools.chain(input_classes, output_classes)
    return set(
        needed_class
        for needed_class in needed_classes
        if needed_class not in classification_code
    )


def _query_source_paths(source: str) -> List[str]:
    protocol = UrlProtocols()
    suffix = protocol.extract_path(source).suffix
    if suffix in KNOWN_FORMATS:
        return [source]
    elif suffix == "":
        return [
            url
            for url in protocol.list(source)
            if protocol.extract_path(url).suffix in KNOWN_FORMATS
        ]
    else:
        raise IOError(
            f"Source path: {source} is not a folder nor a "
            f"{list(KNOWN_FORMATS)} file."
        )


class Pipeline(SequenceClassifier):
    """Class that handles the pipeline.

    This class creates & executes the stages of a pipeline
    """

    def __init__(
        self,
        source: Optional[str] = None,
        classification_codes: Optional[Mapping[str, int]] = None,
        stages: Sequence[Stage] = (),
        stage_name: Optional[str] = None,
    ) -> None:
        super().__init__(stages, stage_name)
        self.source = source
        self.classification_codes = classification_codes or {}

    @property
    def classification_codes(self) -> Mapping[str, int]:
        return self._classification_codes

    @classification_codes.setter
    def classification_codes(self, value: Mapping[str, int]) -> None:
        missing_classes = get_missing_classes(
            value,
            self.input_classes(),
            self.output_classes(),
        )
        if missing_classes:
            raise RuntimeError(
                f"Classification code is missing the following classes: {missing_classes}"
            )
        self._classification_codes = value

    @classmethod
    def options(cls) -> List[Option]:
        return [
            *super().options(),
            Option(
                "classification_codes",
                description="A dictionary the maps the class names to their "
                "corresponding class indices in the point clouds",
                required=False,
                type_cast=dict,
            ),
            Option(
                "source",
                description="The location of the input point cloud(s). Can be a local "
                "or S3 path to a folder or file. Supports LAS/LAZ files",
                required=False,
                type_cast=str,
            ),
        ]

    def execute(self) -> None:
        """Executes the pipeline by making all the stages run their data processing"""
        if self.source is None:
            raise ValueError("Cannot execute a pipeline without setting a `source`")
        source_paths = _query_source_paths(self.source)
        metadata = PipelineMetadata(self.source, self.classification_codes)

        logger.info(f"{len(source_paths)} point cloud(s) to process")
        for i, source_path in enumerate(source_paths, 1):
            parent_file = os.path.basename("_".join(source_path.split("_")[:-1]))
            logger.info(
                f"{i} / {len(source_paths)}: Processing {source_path}",
                extra={"parent_file": parent_file, "source_file": source_path},
            )
            cloud = PointCloud.read_from_path(source_path)

            self.execute_on(cloud, metadata)

            logger.info(
                f"Processing of {source_path} ended",
                extra={
                    "parent_file": parent_file,
                    "status": "SUCCESS",
                    "status_flag": 1,
                    "source_file": source_path,
                },
            )


def override_pipeline_options(
    pipeline_opts: Dict[str, Any], override: Dict[str, Any]
) -> None:
    """Overrides parameters of the pipeline dict using values from the override dict.

    The override dict is a flat dict that looks like this:
    {
        "source": "path_to_file_that_override.laz",
        "ClassifierA.option_1": "new_value,
        "ClassifierA.option_3": "new_value,
        "ClassifierB.option_2": "new_value,
    }

    :param pipeline_opts: dict of the pipeline
    :param override: dict with values to override
    """
    new_source = override.pop("source", None)
    if new_source is not None:
        pipeline_opts["source"] = new_source

    pipeline_stages = {stage["name"]: stage for stage in pipeline_opts["stages"]}
    for key, value in override.items():
        stage_name, opt_name = key.split(".")
        try:
            stage_opts = pipeline_stages[stage_name]
        except KeyError as exception:
            logger.warning("No Stage named '{}' in the pipeline".format(exception))
        else:
            stage_opts[opt_name] = value
